form:Form.form:Scripts:
		function ChangeHorario()
{
	var param = "<HORARIO id=\""+Ctrl("horario").GetXValue()+"\"/>";
	var Escuadras;	
	Escuadras=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("ESCUADRAS"),param);			
	Ctrl("oi_escuadra").setOptions(Escuadras.associatedELE);
	Ctrl("oi_escuadra").SetXValue("");
}

qry:select.qry:xquery:
			for $r in sql('
	SELECT 				
		LEG.oi_personal_emp, 
		EMP.d_empresa,
		LEG.e_numero_legajo,
		SEC.policy
	FROM 
		PER01_PERSONAL as PER, 
		PER02_PERSONAL_EMP as LEG, 
		TTA04_PERSONAL as PER_TTA,
		ORG03_EMPRESAS as EMP,
	  NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC
		{%?(#SOURCE:@horario!='') {% , TTA04_HORARIOSPERS as HOR %} {% %} %}
	JOIN 
		PER.oi_personal INNER LEG.oi_personal,
		LEG.oi_empresa INNER EMP.oi_empresa,
		LEG.oi_personal_emp LEFT OUTER PER_TTA.oi_personal_emp,
		LEG.oi_personal_emp LEFT OUTER SEC.id
		{%?(#SOURCE:@horario!='') {% ,HOR.oi_personal_emp INNER LEG.oi_personal_emp %} {% %} %}
	WHERE 1=1
	{%?(#SOURCE:@activos='1') {% and LEG.oi_indic_activo= \'1\' %} {% %} %}
	{%?(#SOURCE:@empresa!='') {% and LEG.oi_empresa = {#SOURCE:@empresa} %} {% %} %}
	{%?(#SOURCE:@legajo_reloj_desde!='') {% and PER_TTA.e_nro_legajo_reloj >= {#SOURCE:@legajo_reloj_desde} %} {% %} %}
	{%?(#SOURCE:@legajo_reloj_hasta!='') {% and PER_TTA.e_nro_legajo_reloj <= {#SOURCE:@legajo_reloj_hasta} %} {% %} %}
	{%?(#SOURCE:@chksinreloj='1') {% and ISNULL(PER_TTA.e_nro_legajo_reloj) %} {% %} %}
	{%?(#SOURCE:@tarjeta_desde!='') {% and PER_TTA.d_nro_tarjeta >= {#SOURCE:@tarjeta_desde} %} {% %} %}
	{%?(#SOURCE:@tarjeta_hasta!='') {% and PER_TTA.d_nro_tarjeta <= {#SOURCE:@tarjeta_hasta} %} {% %} %}
	{%?(#SOURCE:@chksintarjeta='1') {% and (PER_TTA.d_nro_tarjeta = \'\' or  ISNULL(PER_TTA.d_nro_tarjeta)) %} {% %} %}
	{%?(#SOURCE:@grupo_horario!='') {% and PER_TTA.oi_grupo_hor = {#SOURCE:@grupo_horario} %} {% %} %}
	{%?(#SOURCE:@horario!='') 
		{% and (HOR.oi_horario={#SOURCE:@horario}) 
			 and ((HOR.f_fechaInicio < {NOW()} 
			 AND HOR.f_fechaFin > {NOW()}) OR (HOR.f_fechaInicio < {NOW()} 
			 AND ISNULL(HOR.f_fechaFin)))
			 {%?(#SOURCE:@oi_escuadra!='') 
			 	{% and (HOR.oi_escuadra={#SOURCE:@oi_escuadra}) %} 
			 	{% %} 
			 %}
		%} 
		{% %} 
	%}			
	ORDER BY d_empresa ASC, e_numero_legajo ASC
')/ROWS/ROW
